import { useEffect, useState } from 'react';
import './App.css';

function App() {

  let [articles, setArticles] = useState([]);

  useEffect(() => {
    fetch(`https://newsapi.org/v2/everything?q=karnataka&from=2025-07-07&apiKey=8047ab24c9464bacad8b9841cdd30f85`)
      .then((response) => response.json())
      .then((news) => {
        setArticles(news.articles);
      })
      .catch((err) => {
        console.log(err);

      })
  }, [])


  return (
    <div className="App">
      <h1>News App</h1>
    </div>
  );
}

export default App;
